import{_ as d,o as a,c as i,a6 as e}from"./chunks/framework.wLlb4ebq.js";const b=JSON.parse('{"title":"Routing Rules","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/routing-rules.md","filePath":"concepts/routing-rules.md"}'),r={name:"concepts/routing-rules.md"};function n(o,t,s,l,h,u){return a(),i("div",null,[...t[0]||(t[0]=[e(`<h1 id="routing-rules" tabindex="-1">Routing Rules <a class="header-anchor" href="#routing-rules" aria-label="Permalink to “Routing Rules”">​</a></h1><p>Routing Rules 描述 LD-Notion 在当前系统中如何根据来源、目标、授权、AI 配置和权限等级选择处理路径。这里的规则是对现有 UI、服务层、OperationGuard 和导出适配层行为的文档化约定，不代表存在独立的 routing engine。</p><h2 id="mental-model" tabindex="-1">Mental Model <a class="header-anchor" href="#mental-model" aria-label="Permalink to “Mental Model”">​</a></h2><p>一次导入或 AI 写入请求先收集输入信号，再按优先级选择来源处理器、目标适配器、授权方式、AI 增强路径和权限守卫。最终只有通过 Guard 的路径可以写入 Notion 或 Obsidian。</p><div class="language-mermaid"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Capture[捕获来源数据] --&gt; SourceRoute{Source routing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  SourceRoute --&gt; Normalize[标准化内容]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Normalize --&gt; DestinationRoute{Destination routing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  DestinationRoute --&gt; AuthRoute{Auth routing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  AuthRoute --&gt; AIRoute{AI routing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  AIRoute --&gt; PermissionRoute{Permission routing}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  PermissionRoute --&gt; Guard[OperationGuard]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Guard --&gt;|允许| Write[写入 Notion / Obsidian]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Guard --&gt;|阻止| Fallback[提示、预览或跳过]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Write --&gt; Audit[记录导出状态与审计信息]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Fallback --&gt; Audit</span></span></code></pre></div><h2 id="inputs-and-signals" tabindex="-1">Inputs and Signals <a class="header-anchor" href="#inputs-and-signals" aria-label="Permalink to “Inputs and Signals”">​</a></h2><table tabindex="0"><thead><tr><th>Signal</th><th>来源</th><th>用途</th></tr></thead><tbody><tr><td>source type</td><td>Linux.do、GitHub、Bookmarks、Zhihu、Generic Web</td><td>决定解析器和详情获取方式。</td></tr><tr><td>destination</td><td>Notion database、Notion page、Obsidian</td><td>决定 payload 格式和写入 API。</td></tr><tr><td>auth state</td><td>OAuth、manual token、missing auth</td><td>决定是否可以访问 Notion 或外部服务。</td></tr><tr><td>AI config</td><td>provider、model、enabled、fallback</td><td>决定是否生成摘要、标签、分类或对话式任务结果。</td></tr><tr><td>permission level</td><td>read-only、standard、advanced、admin</td><td>决定是否允许写入、批量整理或危险操作。</td></tr><tr><td>duplicate marker</td><td>已导出记录、sourceId、URL</td><td>决定跳过、更新或创建新条目。</td></tr></tbody></table><h2 id="route-priority" tabindex="-1">Route Priority <a class="header-anchor" href="#route-priority" aria-label="Permalink to “Route Priority”">​</a></h2><ol><li>安全与授权优先于写入目标：没有有效授权时不进入 Notion 写入。</li><li>明确用户选择优先于自动推断：用户指定目标库、页面或 Obsidian 时使用显式选择。</li><li>来源专用解析优先于通用网页解析：已识别来源使用专用字段和详情接口。</li><li>AI 增强是可选步骤：AI 失败不应阻断基础导入。</li><li>OperationGuard 是最终写入边界：所有写入路径都必须经过权限与审计检查。</li></ol><h2 id="decision-tables" tabindex="-1">Decision Tables <a class="header-anchor" href="#decision-tables" aria-label="Permalink to “Decision Tables”">​</a></h2><h3 id="source-routing" tabindex="-1">Source routing <a class="header-anchor" href="#source-routing" aria-label="Permalink to “Source routing”">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Input signal</th><th>Condition</th><th>Route</th><th>Guard</th><th>Fallback</th></tr></thead><tbody><tr><td>1</td><td>当前页面域名与数据结构</td><td>匹配 Linux.do 收藏或帖子页面</td><td>使用 Linux.do 解析与详情获取</td><td>检查读取来源与导出权限</td><td>仅保留列表中可读字段并提示详情缺失。</td></tr><tr><td>2</td><td>GitHub URL 或仓库元信息</td><td>匹配 repository、issue、discussion 或 README</td><td>使用 GitHubAPI / GitHubExporter</td><td>检查 GitHub 请求限制与目标写入权限</td><td>保存 URL、标题和基础元数据，跳过深度内容。</td></tr><tr><td>3</td><td>chrome.bookmarks 可用性</td><td>浏览器书签桥接扩展或独立扩展可用</td><td>使用 BookmarkBridge / BookmarkExporter</td><td>检查扩展权限与用户选择范围</td><td>提示安装桥接扩展或改用手动网页剪藏。</td></tr><tr><td>4</td><td>Zhihu URL 或页面结构</td><td>匹配知乎内容页</td><td>使用 ZhihuAPI 或页面解析</td><td>检查内容可访问性</td><td>使用 Generic Web 摘要路径。</td></tr><tr><td>5</td><td>任意网页 URL</td><td>未匹配专用来源</td><td>使用 Generic Web 剪藏</td><td>检查页面可读内容</td><td>保存标题、URL 和用户选中文本。</td></tr></tbody></table><h3 id="destination-routing" tabindex="-1">Destination routing <a class="header-anchor" href="#destination-routing" aria-label="Permalink to “Destination routing”">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Input signal</th><th>Condition</th><th>Route</th><th>Guard</th><th>Fallback</th></tr></thead><tbody><tr><td>1</td><td>用户目标选择</td><td>选择 Notion database</td><td>转换为 Notion database properties + blocks</td><td>需要 Notion 写入权限与 database access</td><td>降级到预览，不自动创建条目。</td></tr><tr><td>2</td><td>用户目标选择</td><td>选择 Notion page</td><td>转换为 append children 或创建子页面</td><td>需要页面写入权限</td><td>提示重新选择可写页面。</td></tr><tr><td>3</td><td>用户目标选择</td><td>选择 Obsidian</td><td>转换为 Markdown 与 frontmatter</td><td>需要 Obsidian REST API 配置</td><td>保留 Markdown 预览并等待用户复制。</td></tr><tr><td>4</td><td>已保存默认目标</td><td>用户未选择但存在默认 database/page</td><td>使用默认目标</td><td>检查默认目标仍可访问</td><td>要求用户重新配置目标。</td></tr><tr><td>5</td><td>无目标信号</td><td>没有可用目标</td><td>进入 preview-only route</td><td>禁止写入</td><td>仅展示标准化结果。</td></tr></tbody></table><h3 id="auth-routing" tabindex="-1">Auth routing <a class="header-anchor" href="#auth-routing" aria-label="Permalink to “Auth routing”">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Input signal</th><th>Condition</th><th>Route</th><th>Guard</th><th>Fallback</th></tr></thead><tbody><tr><td>1</td><td>Notion OAuth token</td><td>access token 有效</td><td>使用 OAuth NotionTransport</td><td>检查 workspace 与目标 access</td><td>若 401，尝试刷新或提示重新授权。</td></tr><tr><td>2</td><td>refresh token</td><td>access token 过期且 refresh token 可用</td><td>刷新凭据后继续</td><td>检查 state 与本地加密保险箱 / 配置存储一致性</td><td>刷新失败时进入 missing auth。</td></tr><tr><td>3</td><td>manual token</td><td>用户配置 integration token</td><td>使用 manual token 写入</td><td>标记为高级 fallback，需要目标显式授权</td><td>提示优先使用 OAuth。</td></tr><tr><td>4</td><td>外部来源 token</td><td>GitHub 或 Obsidian token 可用</td><td>使用对应来源或目标 API</td><td>检查 token 作用域</td><td>降级为公开页面或本地预览。</td></tr><tr><td>5</td><td>missing auth</td><td>缺少必要凭据</td><td>阻止远程写入</td><td>OperationGuard 返回 auth_required</td><td>显示配置入口和待写入预览。</td></tr></tbody></table><h3 id="ai-routing" tabindex="-1">AI routing <a class="header-anchor" href="#ai-routing" aria-label="Permalink to “AI routing”">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Input signal</th><th>Condition</th><th>Route</th><th>Guard</th><th>Fallback</th></tr></thead><tbody><tr><td>1</td><td>AI enabled + provider configured</td><td>用户启用摘要、标签或分类</td><td>调用 AI provider enrich normalized content</td><td>检查是否包含敏感内容与用户权限</td><td>AI 失败时保留原始内容继续导入。</td></tr><tr><td>2</td><td>AI enabled + agent action</td><td>用户请求对话式整理或批量操作</td><td>进入 AI Agent Loop，再提交 OperationGuard</td><td>写入动作必须二次确认</td><td>降级为只读建议。</td></tr><tr><td>3</td><td>AI disabled</td><td>用户关闭 AI</td><td>跳过 enrich</td><td>无额外 AI guard</td><td>使用来源原始标签和人工输入。</td></tr><tr><td>4</td><td>provider missing</td><td>没有 API key 或模型配置</td><td>跳过 AI route</td><td>不发送外部请求</td><td>提示配置 AI，但不阻断导入。</td></tr><tr><td>5</td><td>AI timeout / quota</td><td>provider 返回错误</td><td>标记 enrich_failed</td><td>审计失败原因</td><td>写入基础 normalized content。</td></tr></tbody></table><h3 id="permission-routing" tabindex="-1">Permission routing <a class="header-anchor" href="#permission-routing" aria-label="Permalink to “Permission routing”">​</a></h3><table tabindex="0"><thead><tr><th>Priority</th><th>Input signal</th><th>Condition</th><th>Route</th><th>Guard</th><th>Fallback</th></tr></thead><tbody><tr><td>1</td><td>permission level</td><td>read-only</td><td>允许读取、搜索、预览</td><td>阻止所有写入</td><td>展示 preview-only 结果。</td></tr><tr><td>2</td><td>permission level</td><td>standard</td><td>允许单条导入和普通追加</td><td>阻止批量删除、覆盖和危险整理</td><td>要求提升权限或拆分为单条操作。</td></tr><tr><td>3</td><td>permission level</td><td>advanced</td><td>允许批量导入与模板化写入</td><td>危险操作需要确认</td><td>进入确认对话。</td></tr><tr><td>4</td><td>permission level</td><td>admin</td><td>允许维护类操作</td><td>仍记录审计事件</td><td>若目标不可达仍阻止写入。</td></tr><tr><td>5</td><td>permission unknown</td><td>无权限等级或配置损坏</td><td>使用 read-only route</td><td>默认拒绝写入</td><td>提示重置权限配置。</td></tr></tbody></table><h2 id="fallback-behavior" tabindex="-1">Fallback Behavior <a class="header-anchor" href="#fallback-behavior" aria-label="Permalink to “Fallback Behavior”">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>默认 fallback</th></tr></thead><tbody><tr><td>未识别来源</td><td>使用 Generic Web 路径，只保存标题、URL、选中文本和基础摘要。</td></tr><tr><td>目标不可写</td><td>停在预览状态，不创建 Notion 或 Obsidian 内容。</td></tr><tr><td>授权失效</td><td>提示重新授权，保留本次 normalized content。</td></tr><tr><td>AI 失败</td><td>跳过 AI enrich，继续基础导入并记录失败原因。</td></tr><tr><td>权限不足</td><td>阻止写入，展示需要的权限等级和用户可执行的替代操作。</td></tr><tr><td>重复内容</td><td>优先跳过；如果用户显式选择更新，则再次进入 Guard。</td></tr></tbody></table><h2 id="implementation-contract" tabindex="-1">Implementation Contract <a class="header-anchor" href="#implementation-contract" aria-label="Permalink to “Implementation Contract”">​</a></h2><ul><li>Routing Rules 接收来源信号、目标选择、授权状态、AI 配置、权限等级和重复检测结果。</li><li>Routing Rules 输出一个用户可解释的处理路径：source adapter、destination adapter、auth strategy、AI enrich mode、permission decision。</li><li>所有写入路径必须经过 OperationGuard。</li><li>所有 fallback 都必须保留用户可见状态，不能静默丢弃内容。</li><li>文档中的 schema 与状态名用于描述跨模块契约，不要求代码中存在同名类型。</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “Troubleshooting”">​</a></h2><table tabindex="0"><thead><tr><th>现象</th><th>可能原因</th><th>处理方式</th></tr></thead><tbody><tr><td>页面只能预览不能写入</td><td>missing auth、read-only permission 或目标不可写</td><td>检查 Notion 授权、目标页面权限和权限等级。</td></tr><tr><td>GitHub 内容只有标题和 URL</td><td>API 限制、仓库不可访问或详情获取失败</td><td>检查 GitHub 访问状态，或接受基础导入结果。</td></tr><tr><td>AI 摘要没有生成</td><td>AI disabled、provider missing、quota 或 timeout</td><td>检查 AI 配置；导入仍会使用基础内容。</td></tr><tr><td>书签导入不可用</td><td>Tampermonkey 无 chrome.bookmarks 权限</td><td>安装书签桥接扩展或使用独立 Chrome 扩展。</td></tr><tr><td>同一内容被跳过</td><td>sourceId 或 URL 命中已导出记录</td><td>在确认重复后选择更新或更换目标集合。</td></tr></tbody></table>`,26)])])}const p=d(r,[["render",n]]);export{b as __pageData,p as default};
